Here's a complete example:

**XAML**
```xml
<ContentPage xmlns="http://schemas.microsoft.com/dotnet/2021/maui"
             xmlns:x="http://schemas.microsoft.com/winfx/2009/xaml"
             x:Class="MyApp.Views.ItemsPage">

    <RefreshView IsRefreshing="{Binding IsRefreshing}"
                 Command="{Binding RefreshCommand}">

        <CollectionView ItemsSource="{Binding Items}"
                        SelectionMode="Single"
                        SelectedItem="{Binding SelectedItem}"
                        SelectionChangedCommand="{Binding ItemSelectedCommand}">
            <CollectionView.ItemTemplate>
                <DataTemplate>
                    <Grid Padding="10">
                        <Label Text="{Binding Name}" FontSize="16" />
                    </Grid>
                </DataTemplate>
            </CollectionView.ItemTemplate>
        </CollectionView>

    </RefreshView>
</ContentPage>
```

**ViewModel**
```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;
    private readonly INavigationService _nav;

    [ObservableProperty]
    private ObservableCollection<Item> _items = new();

    [ObservableProperty]
    private Item? _selectedItem;

    [ObservableProperty]
    private bool _isRefreshing;

    public ItemsViewModel(IApiService api, INavigationService nav)
    {
        _api = api;
        _nav = nav;
    }

    [RelayCommand]
    private async Task Refresh()
    {
        var data = await _api.GetItemsAsync();
        Items = new ObservableCollection<Item>(data);
        IsRefreshing = false;           // stops the spinner
    }

    [RelayCommand]
    private async Task ItemSelected()
    {
        if (SelectedItem is null) return;

        await _nav.NavigateToAsync(
            nameof(DetailPage),
            new Dictionary<string, object> { ["Item"] = SelectedItem });

        SelectedItem = null;            // clear so the same row can be re-selected
    }
}
```

**Key bindings explained:**

| XAML Property | ViewModel Property | Purpose |
|---|---|---|
| `IsRefreshing` | `IsRefreshing` | Two-way: set `false` to dismiss the spinner |
| `Command` (RefreshView) | `RefreshCommand` | Fires on pull-to-refresh |
| `ItemsSource` | `Items` | The data collection |
| `SelectedItem` | `SelectedItem` | Two-way: tracks current selection |
| `SelectionChangedCommand` | `ItemSelectedCommand` | Fires when selection changes; navigates to detail |

**Things to remember:**
- Set `SelectedItem = null` after navigation so the same item can be tapped again.
- Set `IsRefreshing = false` at the end of your refresh logic — otherwise the spinner stays visible.
- `SelectionMode="Single"` ensures only one item is selected at a time. Use `"Multiple"` + `SelectedItems` if you need multi-select.
- The example uses **CommunityToolkit.Mvvm** source generators (`[ObservableProperty]`, `[RelayCommand]`), which auto-generate the `INotifyPropertyChanged` plumbing and `ICommand` wrappers.
